  </svg>
  </div>
  <div class="vi">
  <svg viewBox="0 0 700 390" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Cấu Trúc Khối Lượng Crypto, Nửa Cuối 2025 — Phái Sinh Chạy Gấp 2,8 Lần Giao Ngay</text>
    <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">Ước tính khối lượng trung bình hàng ngày · Nguồn: CCData / CoinDesk Data</text>
    <line x1="60" y1="330" x2="640" y2="330" stroke="#71717a" stroke-width="1.5"/>
